-- Normaliza o podio provisorio apenas quando ainda nao houver definicao oficial.
UPDATE public.matches AS target
SET
  tenant_id = NULL,
  group_id = NULL,
  team_a = seed.team_a,
  team_b = seed.team_b,
  team_a_flag = seed.team_a_flag,
  team_b_flag = seed.team_b_flag,
  score_a = seed.score_a,
  score_b = seed.score_b,
  started_at = seed.started_at,
  updated_at = now()
FROM (
  VALUES
    ('00000000-0000-0000-0000-9999a0d11111', '1º Lugar', 'Campeão', '🏆', '🏆', 36, 0, '2026-07-19T12:00:00.000Z'),
    ('00000000-0000-0000-0000-9999a0d22222', '2º Lugar', 'Vice-Campeão', '🥈', '🥈', 24, 0, '2026-07-19T12:00:00.000Z'),
    ('00000000-0000-0000-0000-9999a0d33333', '3º Lugar', '3º Colocado', '🥉', '🥉', 32, 0, '2026-07-19T12:00:00.000Z'),
    ('00000000-0000-0000-0000-9999a0d44444', '4º Lugar', '4º Colocado', '🏅', '🏅', 42, 0, '2026-07-19T12:00:00.000Z')
) AS seed(id, team_a, team_b, team_a_flag, team_b_flag, score_a, score_b, started_at)
WHERE target.id = seed.id
  AND target.id IN ('00000000-0000-0000-0000-9999a0d11111', '00000000-0000-0000-0000-9999a0d22222', '00000000-0000-0000-0000-9999a0d33333', '00000000-0000-0000-0000-9999a0d44444')
  AND target.status = 'scheduled'
  AND target.score_a IS NULL
  AND target.score_b IS NULL;
